ModuleDefinition getModuleDefinitionById(String id) {
  return allModuleDefinitions.firstWhere((item) => item.id == id);
}

ModuleFieldDefinition f(
  String key,
  String label, {
  ModuleValueType type = ModuleValueType.text,
  bool required = false,
}) {
  return ModuleFieldDefinition(
    key: key,
    label: label,
    type: type,
    required: required,
  );
}

ModuleDefinition _m({
  required String id,
  required String title,
  required String category,
  required String subtitle,
  required IconData icon,
  required Color color,
  required String basePath,
  List<ModuleFieldDefinition> search = const [],
  List<String> titleFields = const [],
  List<ModuleFieldDefinition> display = const [],
  List<ModuleFieldDefinition> edit = const [],
  bool approval = false,
  bool useList = false,
  bool pageResult = true,
  bool detail = true,
  bool create = true,
  bool update = true,
  bool delete = true,
}) {
  return ModuleDefinition(
    id: id,
    title: title,
    category: category,
    subtitle: subtitle,
    icon: icon,
    color: color,
    pagePath: useList ? null : '$basePath/page',
    listPath: useList ? '$basePath/list' : null,
    detailPath: detail ? '$basePath/get' : null,
    createPath: create ? '$basePath/create' : null,
    updatePath: update ? '$basePath/update' : null,
    deletePath: delete ? '$basePath/delete' : null,
    submitPath: approval ? '$basePath/submit' : null,
    pageResult: pageResult,
    searchFields: search,
    titleFields: titleFields,
    displayFields: display,
    editableFields: edit,
    supportsApproval: approval,
  );
}
